","new_string":"import app.k9mail.legacy.account.AccountManager
import app.k9mail.legacy.preferences.SettingsChangePublisher
import com.fsck.k9.K9
import com.fsck.k9.Preferences

/**
 * Configures the unified inbox after an account has been added.
 */
class UnifiedInboxConfigurator(
    private val accountManager: AccountManager,
    private val preferences: Preferences,
    private val settingsChangePublisher: SettingsChangePublisher,
) {
    fun configureUnifiedInbox() {
        val finishedAccountsCount = accountManager.getAccounts().count { it.isFinishedSetup }
        if (finishedAccountsCount < 2) return

        val storage = preferences.storage
        val isShowUnifiedInboxConfigured =
            storage.contains("showUnifiedInbox") || storage.contains("hideSpecialAccounts")

        val shouldEnableUnifiedInbox = when {
            // Enable Unified Inbox when a second account has been added.
            finishedAccountsCount == 2 -> !K9.isShowUnifiedInbox

            // Adding further accounts should preserve existing settings. Only auto-enable if it has never been
            // configured (e.g. due to an interrupted setup process where settings weren't saved).
            else -> !isShowUnifiedInboxConfigured
        }

        if (!shouldEnableUnifiedInbox) return

        K9.isShowUnifiedInbox = true

        // Persist immediately so the setting survives process death right after setup.
        preferences.createStorageEditor()
            .putBoolean("showUnifiedInbox", true)
            .commit()

        // Notify subscribers (e.g. the navigation drawer) that settings have changed.
        settingsChangePublisher.publish()
    }
}
