import app.k9mail.legacy.account.Account
import app.k9mail.legacy.account.AccountManager
import app.k9mail.legacy.preferences.SettingsChangePublisher
import assertk.assertThat
import assertk.assertions.isFalse
import assertk.assertions.isTrue
import com.fsck.k9.K9
import com.fsck.k9.K9RobolectricTest
import com.fsck.k9.Preferences
import com.fsck.k9.preferences.Storage
import org.junit.After
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever

class UnifiedInboxConfiguratorTest : K9RobolectricTest() {
    private val accountManager = mock<AccountManager>()
    private val preferences = mock<Preferences>()
    private val storageEditor = mock<StorageEditor>()
    private val settingsChangePublisher = mock<SettingsChangePublisher>()

    private val unifiedInboxConfigurator = UnifiedInboxConfigurator(
        accountManager = accountManager,
        preferences = preferences,
        settingsChangePublisher = settingsChangePublisher,
    )

    private val originalShowUnifiedInbox = K9.isShowUnifiedInbox

    @Before
    fun setUp() {
        K9.isShowUnifiedInbox = false

        whenever(preferences.createStorageEditor()).thenReturn(storageEditor)
        whenever(storageEditor.putBoolean(any(), any())).thenReturn(storageEditor)
        whenever(storageEditor.commit()).thenReturn(true)
    }

    @After
    fun tearDown() {
        K9.isShowUnifiedInbox = originalShowUnifiedInbox
    }

    @Test
    fun `configureUnifiedInbox() should not enable unified inbox when there is only one account`() {
        whenever(accountManager.getAccounts()).thenReturn(listOf(createFinishedAccount("a")))
        whenever(preferences.storage).thenReturn(Storage(emptyMap()))

        unifiedInboxConfigurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
        verify(storageEditor, never()).putBoolean(any(), any())
        verify(settingsChangePublisher, never()).publish()
    }

    @Test
    fun `configureUnifiedInbox() should enable unified inbox when a second account has been added`() {
        whenever(accountManager.getAccounts()).thenReturn(
            listOf(createFinishedAccount("a"), createFinishedAccount("b")),
        )
        whenever(preferences.storage).thenReturn(Storage(emptyMap()))

        unifiedInboxConfigurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
        verify(storageEditor).putBoolean("showUnifiedInbox", true)
        verify(storageEditor).commit()
        verify(settingsChangePublisher).publish()
    }

    @Test
    fun `configureUnifiedInbox() should not override existing unified inbox setting when adding further accounts`() {
        whenever(accountManager.getAccounts()).thenReturn(
            listOf(
                createFinishedAccount("a"),
                createFinishedAccount("b"),
                createFinishedAccount("c"),
            ),
        )
        whenever(preferences.storage).thenReturn(Storage(mapOf("showUnifiedInbox" to "false")))

        unifiedInboxConfigurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
        verify(storageEditor, never()).putBoolean(any(), any())
        verify(settingsChangePublisher, never()).publish()
    }

    @Test
    fun `configureUnifiedInbox() should enable unified inbox when setting has never been configured`() {
        whenever(accountManager.getAccounts()).thenReturn(
            listOf(
                createFinishedAccount("a"),
                createFinishedAccount("b"),
                createFinishedAccount("c"),
            ),
        )
        whenever(preferences.storage).thenReturn(Storage(emptyMap()))

        unifiedInboxConfigurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
        verify(storageEditor).putBoolean("showUnifiedInbox", true)
        verify(storageEditor).commit()
        verify(settingsChangePublisher).publish()
    }

    private fun createFinishedAccount(uuid: String): Account {
        return Account(uuid).apply { markSetupFinished() }
    }
}
